To create a smooth snake game in C using images for animation, you'll need to use a library that handles graphics and animation. I'll guide you through the process using the SDL (Simple DirectMedia Layer) library, which is a popular choice for game development.

**Prerequisites:**

1. Install SDL development libraries:
	* On Linux: `sudo apt-get install libsdl2-dev` (Ubuntu-based) or `sudo yum install SDL2-devel` (RHEL-based)
	* On Windows: Download and install the SDL2 development library from the official website
	* On macOS: Install SDL2 using Homebrew: `brew install sdl2`
2. Install a C compiler (if you haven't already): `gcc` or `clang`

**Create a new project:**

Create a new directory for your project and create the following files:

1. `snake.c` (main file)
2. `snake.h` (header file)
3. `snake_resources` directory (for images and other resources)

**snake.h:**
```c
#ifndef SNAKE_H
#define SNAKE_H

#include <SDL2/SDL.h>

// Define constants
#define SCREEN_WIDTH 640
#define SCREEN_HEIGHT 480
#define BLOCK_SIZE 20

// Define game states
typedef enum {
    GAME_RUNNING,
    GAME_OVER
} GameState;

// Define snake structure
typedef struct {
    int x, y;
    int length;
    SDL_Texture* head;
    SDL_Texture* body;
} Snake;

// Function prototypes
void init_game();
void update_game();
void render_game();
void handle_events();
void game_loop();

#endif // SNAKE_H
```
**snake.c:**
```c
#include "snake.h"
#include <SDL2/SDL_image.h>

// Initialize game
void init_game() {
    // Initialize SDL
    SDL_Init(SDL_INIT_VIDEO);
    // Create window
    SDL_Window* window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, SCREEN_WIDTH, SCREEN_HEIGHT, SDL_WINDOW_SHOWN);
    // Create renderer
    SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);
    // Load images
    SDL_Texture* head_texture = IMG_LoadTexture(renderer, "snake_head.png");
    SDL_Texture* body_texture = IMG_LoadTexture(renderer, "snake_body.png");
    // Initialize snake
    Snake snake = {0, 0, 0, head_texture, body_texture};
    // Set game state
    GameState game_state = GAME_RUNNING;
}

// Update game logic
void update_game() {
    // Update snake movement
    // ...
}

// Render game
void render_game(SDL_Renderer* renderer, Snake* snake) {
    // Clear screen
    SDL_RenderClear(renderer);
    // Draw snake
    for (int i = 0; i < snake->length; i++) {
        SDL_Rect rect = {snake->x + i * BLOCK_SIZE, snake->y, BLOCK_SIZE, BLOCK_SIZE};
        SDL_RenderCopy(renderer, snake->body, NULL, &rect);
    }
    // Draw head
    SDL_Rect head_rect = {snake->x, snake->y, BLOCK_SIZE, BLOCK_SIZE};
    SDL_RenderCopy(renderer, snake->head, NULL, &head_rect);
    // Update screen
    SDL_RenderPresent(renderer);
}

// Handle events
void handle_events() {
    // Handle user input (e.g., arrow keys)
    // ...
}

// Game loop
void game_loop() {
    init_game();
    while (game_state == GAME_RUNNING) {
        handle_events();
        update_game();
        render_game(renderer, &snake);
    }
    // Clean up
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();
}

int main() {
    game_loop();
    return 0;
}
```
