Here is a simple C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:
```cpp
#include <iostream>
#include <fstream>
#include <string>
#include <map>

int main() {
    std::string filename = "example.txt"; // replace with your file name
    std::string targetWord = "example"; // replace with the word you want to count

    std::ifstream file(filename);
    if (!file.is_open()) {
        std::cerr << "Error opening file!" << std::endl;
        return 1;
    }

    std::map<std::string, int> wordCounts;
    std::string line;
    while (std::getline(file, line)) {
        std::istringstream iss(line);
        std::string word;
        while (iss >> word) {
            if (word == targetWord) {
                wordCounts[word]++;
            }
        }
    }

    file.close();

    std::cout << "Word '" << targetWord << "' occurs " << wordCounts[targetWord] << " times in the file." << std::endl;

    return 0;
}
```
Here's how the program works:

1. Open the file specified by `filename` and check if it's successfully opened. If not, print an error message and exit.
2. Create an empty `std::map` called `wordCounts` to store the word counts.
3. Read the file line by line using `std::getline`. For each line:
	* Split the line into individual words using `std::istringstream`.
	* Iterate over each word and check if it matches the target word. If it does, increment the count in `wordCounts`.
4. Close the file.
5. Print the final count of the target word occurrences.

Replace `example.txt` with your actual file name and `example` with the word you want to count. Compile and run the program to see the result!

Here is a Python function that uses dynamic programming to find the longest common subsequence (LCS) of two input strings:

```python
def longest_common_subsequence(X, Y):
    m = len(X)
    n = len(Y)

    # Create a table to store lengths of LCS of substrings
    L = [[0] * (n + 1) for _ in range(m + 1)]

    # Fill the table in bottom-up manner
    for i in range(m + 1):
        for j in range(n + 1):
            if i == 0 or j == 0:
                L[i][j] = 0
            elif X[i - 1] == Y[j - 1]:
                L[i][j] = L[i - 1][j - 1] + 1
            else:
                L[i][j] = max(L[i - 1][j], L[i][j - 1])

    # Reconstruct the LCS from the table
    result = []
    i, j = m, n
    while i > 0 and j > 0:
        if X[i - 1] == Y[j - 1]:
            result.append(X[i - 1])
            i -= 1
            j -= 1
        elif L[i - 1][j] > L[i][j - 1]:
            i -= 1
        else:
            j -= 1

    # Return the LCS in reverse order
    return ''.join(reversed(result))

# Test the function
X = "AGGTAB"
Y = "GXTXAYB"
print("Longest Common Subsequence:", longest_common_subsequence(X, Y))

Here is an implementation of a queue using two stacks in Python:

```Python
class Queue:
    def __init__(self):
        self.stack1 = []
        self.stack2 = []

    def enqueue(self, item):
        self.stack1.append(item)

    def dequeue(self):
        if not self.stack2:
            while self.stack1:
                self.stack2.append(self.stack1.pop())
        return self.stack2.pop()

    def is_empty(self):
        return len(self.stack1) == 0 and len(self.stack2) == 0

    def size(self):
        return len(self.stack1) + len(self.stack2)

    def peek(self):
        if not self.stack2:
            while self.stack1:
                self.stack2.append(self.stack1.pop())
        return self.stack2[-1]

# Testing the Queue
q = Queue()
q.enqueue(1)
q.enqueue(2)
q.enqueue(3)
print(q.dequeue())  # Output: 1
print(q.peek())     # Output: 2
print(q.size())     # Output: 2
print(q.is_empty()) # Output: False
